"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[856],{66799:e=>{e.exports=JSON.parse('{"url":"ppdocs/openapi.yml","themeId":"theme-redoc","isSpecFile":false,"normalizeUrl":true,"spec":{"openapi":"3.1.0","info":{"title":"PPDRIVE","version":"0.26.71","summary":"PPDRIVE - an integratable and secure file manager","description":"PPDRIVE is a powerful, standalone file manager written in Rust,\\ndesigned for seamless integration into other applications\\nvia a RESTful API.\\n"},"servers":[{"url":"http://localhost:5000","description":"A local demo server"}],"security":[{"clientKey":[]},{"userAuth":[]}],"paths":{"/{asset_type}/{asset_path}":{"get":{"deprecated":false,"summary":"Get Asset","description":"Serve an asset (file or folder) from the provided asset path.\\n","parameters":[{"name":"asset_type","in":"path","schema":{"type":"string","enum":["File","Folder"]},"description":"This is the type of asset you\'re trying to retrieve. Set to `File`\\nif you\'re trying to get a file and `Folder` if you\'re trying to get a folder\\n","required":true},{"name":"asset_path","in":"path","schema":{"type":"string"},"description":"This either the asset\'s original path or a custom_path set when\\nthe asset was created.\\n","required":true}],"responses":{"200":{"description":"If the asset is a folder, we return browser-compatible html content\\nrendering a list of folder contents.\\n\\nIf the asset is a file, we return the file raw data with its\\nrespective mime type in `Content-Type` header for browser rendering.\\n"}}}},"/client/user/register":{"post":{"deprecated":false,"summary":"Register User","description":"Register a new user. \\\\\\nIf you\'re connecting PPDRIVE to an exisiting app (likely a reason to\\nuse clients), it\'s perfect to call this route before/after you\'ve\\nregistered your user and bind the returned `id` to your app\'s user.\\nSee responses.200\\n","tags":["Client Routes"],"security":[{"clientKey":[]}],"requestBody":{"description":"Options for creating a new user","required":true,"content":{"application/json":{"schema":{"$ref":"#/components/schemas/CreateUserOptions"}}}},"responses":{"200":{"description":"User\'s login details, including the token and expiration.\\n","content":{"appplication/json":{"schema":{"$ref":"#/components/schemas/LoginToken"}}}}}}},"/client/user/login":{"post":{"deprecated":false,"summary":"Login User","description":"Authenticate a user and get their JWT.\\n`password` field is not required for this route.\\n","tags":["Client Routes"],"security":[{"clientKey":[]}],"requestBody":{"description":"Options for creating a new user","required":true,"content":{"application/json":{"schema":{"$ref":"#/components/schemas/LoginCredentials"}}}},"responses":{"200":{"description":"User\'s login details, including the token and expiration.","content":{"appplication/json":{"schema":{"type":"string","description":"id of the new user.","example":"3e7d53b-dd7f-464e-a3b9-7b1ec2d71ce5"}}}}}}},"/client/user/{id}":{"delete":{"deprecated":false,"summary":"Delete User","description":"Delete a user with the provided `id`.","tags":["Client Routes"],"security":[{"clientKey":[]}],"parameters":[{"required":false,"in":"path","name":"id","schema":{"type":"string","decription":"ID of the user to be deleted."}}],"responses":{"200":{"description":"Operation success message.","content":{"appplication/json":{"schema":{"type":"string","description":"a message that indicates the operation was successful.","example":"operation successful"}}}}}}},"/user":{"get":{"deprecated":false,"summary":"Get Current User","description":"Retrieve details about the currently logged user.","tags":["Protected Routes"],"security":[{"userAuth":[]}],"responses":{"200":{"description":"Current user details.","content":{"appplication/json":{"schema":{"$ref":"#/components/schemas/UserDetails"}}}}}}},"/asset":{"post":{"deprecated":false,"summary":"Create or Upload Asset","description":"Create a new asset. If the asset already exists, it will be updated.\\n\\nIt\'s important for PPDRIVE to keep record of every asset and their\\nancestors in the filesystem. Therefore, this route traverses the asset\\n`path` provided in `options`, if no record is found for any of its\\nparent within the file hierarchy, we create the record and the respective\\nasset. You can disable this behavior by settting `options.create_parents`\\nto false.\\n","tags":["Protected Routes"],"security":[{"userAuth":[]}],"requestBody":{"description":"Options for creating the new asset","required":true,"content":{"application/multipart":{"schema":{"$ref":"#/components/schemas/CreateAssetOptions"}}}},"responses":{"200":{"description":"User\'s login details, including the token and expiration.\\n","content":{"appplication/json":{"schema":{"$ref":"#/components/schemas/LoginToken"}}}}}}}},"components":{"securitySchemes":{"clientKey":{"type":"apiKey","scheme":"https","in":"header","name":"x-ppd-client"},"userAuth":{"type":"http","scheme":"bearer","bearerFormat":"Bearer","in":"header","name":"authorization"}},"schemas":{"CreateUserOptions":{"type":"object","properties":{"role":{"type":"string","enum":["Basic","Manager"],"description":"The user\'s role"},"partition":{"type":"string","description":"Create a dedicated partition for the user named by value provided.\\nIf this is not specified, user\'s assets will be stored in application\'s\\nroot partition. Partition name must be unique for every user. If the\\nvalue is already take, this call will return an error.\\n"},"partition_size":{"type":"integer","description":"Max size (in bytes) to be assiged to the user\'s partition. This\\nshould be set only if `partition` is set. Otherwise, it would be\\nignored.\\n"}},"example":{"role":"Creator","partition":"prodbyola"},"required":["role"]},"LoginCredentials":{"type":"object","properties":{"id":{"type":"string","description":"This could be the user\'s id or email address."},"password":{"type":"string","description":"The user\'s password. Password is optional if you\'re not coming\\nthough a Client Route.\\n"},"exp":{"type":"integer","description":"Optional expiration period for user\'s token (in seconds). This\\ndefaults to 5 hours if not set. We\'re working on making the default\\nvalue configurable.\\n"}},"example":{"id":"3e7d53b-dd7f-464e-a3b9-7b1ec2d71ce5","password":"MyUserPassword","exp":5600},"required":["id"]},"LoginToken":{"type":"object","properties":{"token":{"type":"string","description":"The user\'s JWT for subsequent authorization."},"exp":{"type":"integer","description":"Token expiration (in seconds)."}}},"UserDetails":{"type":"object","properties":{"id":{"type":"string"},"email":{"type":"string"},"partition":{"type":"string"},"partition_size":{"type":"integer"},"created_at":{"type":"string"}}},"CreateAssetOptions":{"type":"object","properties":{"path":{"type":"string,","description":"The relative path where we save user\'s asset."},"asset_type":{"type":"string","description":"The type of asset - whether it\'s a file or folder","enum":["File","Folder"]},"public":{"type":"boolean","description":"Asset\'s visibility. \\\\\\nPublic assets can be accessed by everyone. Private assets\\ncan only be accessed by users with `Read` permission.\\n"},"custom_path":{"type":"string","description":"Set a custom path for your asset instead of the one auto-generated\\nfrom `path`. This useful if you\'d like to conceal your original asset\\npath. `custom_path` is unique to each asset and is available if no other\\nasset is already using it in the entire app.\\n\\nYour original asset path makes asset url look like this\\n`https://mydrive.com/images/somewhere/my-image.png/`. Using\\ncustom path, you can conceal the original path:\\n`https://mydrive.com/custom-path`\\n"},"create_parents":{"type":"boolean","description":"Whether to traverse path and create parent assets if they do\\ndo not exist.\\n"},"sharing":{"type":"array","items":{"$ref":"#/components/schemas/AssetSharing"},"description":"Users to share this asset with. This can only be set if `public`\\noption is `false`. Otherwise, it\'ll be ignored. Also, you cannot\\nshare asset with asset owner. This will also be ignored.\\n"}}},"AssetSharing":{"type":"object","properties":{"user_id":{"type":"string"},"permissions":{"type":"array","items":{"type":"string","enum":["Create","Read","Update","Delete"]}}}}}},"tags":[{"client":null,"name":"Client Routes","description":"Client Routes are accesible only to a verifiable PPDRIVE `Client`.\\nA client is an external application capable of authorizing users\\nand managing assets on PPDRIVE.\\n\\nTo access these routes, you need to provide your client\'s `token`\\nby adding the token to `x-ppd-client` header of your requests.\\nYou can generate a client token by running `ppdrive create_client\\n{client_name}` or via the Admin UI.\\n\\n<b style=\\"color:red;\\">IMPORTANT!</b> Client tokens give administrative\\naccess to anyone who possesses it. **DO NOT SHARE YOUR CLIENT TOKEN**.\\nThis means you should ONLY access client routes from your application\\nserver.\\n\\nIf your client token is compromised (or for any other reason), you can\\nregenerate a client token by running `ppdrive new_token {client_id}`.\\n"},{"manager":null,"name":"Protected Routes","description":"Protected Routes are accesible only to a user with `Manage` or `Admin`\\nrole. The `user_role` is assigned when a client or admin [creates a new\\nuser](/#tag/Client-Routes/paths/~1client~1user~1register/post).\\n\\nThe `Protected` must be logged in before they can access this route. Call\\nclient\'s [login route](#tag/Client-Routes/paths/~1client~1user~1login/post)\\nto get a user\'s Bearer Token and pass the token to `Authorization` header\\nof your request in the format `Bearer {token}`.\\n"}]}}')}}]);